'use client'
import { useProductStore } from '@/store/useProductStore'
import { AddProductModal } from '@/components/products/AddProductModal'
import { TrashIcon, PencilIcon } from '@heroicons/react/24/outline'

export default function ProductsPage() {
  const products = useProductStore((state) => state.products)
  const deleteProduct = useProductStore((state) => state.deleteProduct)

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-primary">Products Management</h1>
        <AddProductModal />
      </div>

      {products.length > 0 ? (
        <div className="grid gap-4">
          {products.map((product) => (
            <div key={product.id} className="neumorphic p-6 flex items-center justify-between">
              <div className="flex-1">
                <div className="flex items-center gap-4">
                  <div>
                    <h3 className="text-lg font-semibold text-primary">{product.name}</h3>
                    <p className="text-secondary">{product.category}</p>
                  </div>
                  <div className="text-sm text-secondary">
                    <span className="neumorphic-inset px-3 py-1 rounded-lg">
                      {product.stock} {product.unit} available
                    </span>
                  </div>
                </div>
              </div>
              
              <div className="flex items-center gap-4">
                <div className="text-right">
                  <div className="text-2xl font-bold text-primary">${product.price.toFixed(2)}</div>
                  <div className="text-sm text-secondary">per {product.unit}</div>
                </div>
                
                <div className="flex gap-2">
                  <button className="neumorphic-flat hover:neumorphic-pressed p-2 rounded-lg transition-all">
                    <PencilIcon className="size-4" />
                  </button>
                  <button 
                    onClick={() => deleteProduct(product.id)}
                    className="neumorphic-flat hover:neumorphic-pressed p-2 rounded-lg transition-all text-red-500"
                  >
                    <TrashIcon className="size-4" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="neumorphic p-12 text-center">
          <div className="text-secondary mb-4">No products available</div>
          <p className="text-sm text-muted">Click "Add Product" to create your first product</p>
        </div>
      )}
    </div>
  )
}